VALUES
  ('policepromo-8b7f1efc-moex-00039', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-113-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '下列有關國家賠償法制之敘述，何者正確？', '["國家賠償法所稱公務員，僅限於依公務人員任用法任用之人員", "於開放之山域自然公物內之公共設施，經管理機關已就使用該設施為適當之警告或標示，而人民仍從事 冒險或具危險性活動，致其身體或財產遭受損害時，國家仍應負完全之損害賠償責任", "警察人員執行職務違法使用警械，致侵害人民自由或權利時，不適用國家賠償法賠償", "警察人員執行職務如因重大過失違法使用警械，賠償義務機關不得向其求償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:25+00:00", "source_pdf_sha1": "d5cbcf5a16ce", "answer_pdf_sha1": "679249538eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113170", "c": "101", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "113", "exam_name": "113年警察人員升官等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
